object AppLogger {
    private const val MAX_LOG_CHUNK = 4000

    fun init(debug: Boolean = true) {
        if (Timber.forest().isEmpty()) {
            Timber.plant(ProductionVerboseTree(debug))
        }
    }

    fun v(tag: String, message: String, throwable: Throwable? = null) = log(Log.VERBOSE, tag, message, throwable)
    fun d(tag: String, message: String, throwable: Throwable? = null) = log(Log.DEBUG, tag, message, throwable)
    fun i(tag: String, message: String, throwable: Throwable? = null) = log(Log.INFO, tag, message, throwable)
    fun w(tag: String, message: String, throwable: Throwable? = null) = log(Log.WARN, tag, message, throwable)
    fun e(tag: String, message: String, throwable: Throwable? = null) = log(Log.ERROR, tag, message, throwable)

    fun authAttempt(
        username: String?,
        method: String,
        success: Boolean,
        reason: String? = null,
        metadata: Map<String, Any?> = emptyMap()
    ) {
        val safeUsername = username ?: "null"
        val meta = metadata.entries.joinToString(", ") { "${it.key}=${it.value}" }
        val msg = buildString {
            append("AUTH_ATTEMPT method=").append(method)
            append(" username=").append(safeUsername)
            append(" success=").append(success)
            if (!reason.isNullOrBlank()) append(" reason=").append(reason)
            if (meta.isNotBlank()) append(" metadata={").append(meta).append("}")
        }
        if (success) i("AuthLogger", msg) else w("AuthLogger", msg)
    }

    fun dbQuery(
        sql: String,
        parameters: List<Any?> = emptyList(),
        durationMs: Long? = null,
        rowsAffected: Int? = null
    ) {
        val params = parameters.joinToString(prefix = "[", postfix = "]") { it?.toString() ?: "null" }
        val msg = buildString {
            append("DB_QUERY sql=").append(sql)
            append(" params=").append(params)
            if (durationMs != null) append(" durationMs=").append(durationMs)
            if (rowsAffected != null) append(" rowsAffected=").append(rowsAffected)
        }
        v("DatabaseLogger", msg)
    }

    fun exception(tag: String = "ExceptionLogger", throwable: Throwable, context: String? = null) {
        val msg = buildString {
            append("EXCEPTION")
            if (!context.isNullOrBlank()) append(" context=").append(context)
            append('\n').append(Log.getStackTraceString(throwable))
        }
        e(tag, msg, throwable)
    }

    private fun log(priority: Int, tag: String, message: String, throwable: Throwable?) {
        val fullMessage = if (throwable != null && !message.contains(Log.getStackTraceString(throwable))) {
            "$message\n${Log.getStackTraceString(throwable)}"
        } else {
            message
        }

        if (fullMessage.length <= MAX_LOG_CHUNK) {
            Timber.tag(tag).log(priority, fullMessage)
            return
        }

        var start = 0
        while (start < fullMessage.length) {
            val end = (start + MAX_LOG_CHUNK).coerceAtMost(fullMessage.length)
            Timber.tag(tag).log(priority, fullMessage.substring(start, end))
            start = end
        }
    }
}

class ProductionVerboseTree(private val verboseEnabled: Boolean = true) : Timber.Tree() {
    override fun isLoggable(tag: String?, priority: Int): Boolean {
        return verboseEnabled || priority >= Log.INFO
    }

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val safeTag = tag ?: "AppLogger"
        when (priority) {
            Log.VERBOSE -> Log.v(safeTag, message, t)
            Log.DEBUG -> Log.d(safeTag, message, t)
            Log.INFO -> Log.i(safeTag, message, t)
            Log.WARN -> Log.w(safeTag, message, t)
            Log.ERROR -> Log.e(safeTag, message, t)
            Log.ASSERT -> Log.wtf(safeTag, message, t)
            else -> Log.d(safeTag, message, t)
        }
    }
}

class ApiLoggingInterceptor(
    private val logHeaders: Boolean = true,
    private val logBodies: Boolean = true
) : Interceptor {

    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        logRequest(request)

        val startNs = System.nanoTime()
        return try {
            val response = chain.proceed(request)
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs)
            logResponse(response, tookMs)
            response
        } catch (t: Throwable) {
            AppLogger.exception(
                tag = "ApiLogger",
                throwable = t,
                context = "HTTP FAILED ${request.method} ${request.url}"
            )
            throw t
        }
    }

    private fun logRequest(request: Request) {
        val bodyString = if (logBodies) request.body?.safeReadBodyAsString() ?: "" else "<body logging disabled>"
        val headersString = if (logHeaders) headersToString(request.headers) else "<header logging disabled>"

        val msg = buildString {
            append("API_REQUEST")
            append("\nurl=").append(request.url)
            append("\nmethod=").append(request.method)
            append("\nheaders=").append(headersString)
            append("\nbody=").append(bodyString)
        }
        AppLogger.v("ApiLogger", msg)
    }

    private fun logResponse(response: Response, tookMs: Long) {
        val peekedBody = if (logBodies) {
            try {
                response.peekBody(Long.MAX_VALUE).string()
            } catch (_: Throwable) {
                "<unable to read response body>"
            }
        } else {
            "<body logging disabled>"
        }

        val headersString = if (logHeaders) headersToString(response.headers) else "<header logging disabled>"

        val msg = buildString {
            append("API_RESPONSE")
            append("\nurl=").append(response.request.url)
            append("\nmethod=").append(response.request.method)
            append("\ncode=").append(response.code)
            append("\nmessage=").append(response.message)
            append("\nsuccessful=").append(response.isSuccessful)
            append("\ndurationMs=").append(tookMs)
            append("\nheaders=").append(headersString)
            append("\nbody=").append(peekedBody)
        }
        AppLogger.v("ApiLogger", msg)
    }

    private fun headersToString(headers: Headers): String {
        if (headers.size == 0) return "{}"
        return buildString {
            append("{")
            headers.names().forEachIndexed { index, name ->
                append(name).append("=").append(headers[name])
                if (index < headers.names().size - 1) append(", ")
            }
            append("}")
        }
    }
}

object LoggingOkHttpFactory {
    fun create(): OkHttpClient {
        return OkHttpClient.Builder()
            .addInterceptor(ApiLoggingInterceptor(logHeaders = true, logBodies = true))
            .build()
    }
}

object DatabaseLogger {
