    fun logQueryResult(sql: String, params: List<Any?>, durationMs: Long, rowsAffected: Int? = null) {
        AppLogger.dbQuery(sql = sql, parameters = params, durationMs = durationMs, rowsAffected = rowsAffected)
    }

    fun logException(sql: String, params: List<Any?>, throwable: Throwable) {
        AppLogger.exception(
            tag = "DatabaseLogger",
            throwable = throwable,
            context = "DB query failed sql=$sql params=$params"
