private fun RequestBody.safeReadBodyAsString(): String {
    return try {
        val buffer = Buffer()
        writeTo(buffer)
        val charset = contentType().charsetOrUtf8()
        buffer.readString(charset)
    } catch (e: Exception) {
        "<unable to read request body: ${e.message}>"
    }
}

private fun MediaType?.charsetOrUtf8(): Charset {
    return this?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
}

